#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16

kernel void hotspot(
    int num_iterations,
    const global float* power,
    const global float* temp,
    global float* result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    float amb_temp = 80.0f;

    int blockCol = get_group_id(0);
    int blockRow = get_group_id(1);
    int localCol = get_local_id(0);
    int localRow = get_local_id(1);

    int c_start = blockCol * BLOCK_SIZE;
    int r_start = blockRow * BLOCK_SIZE;

    for (int iter = 0; iter < num_iterations; iter++) {
        for (int local_r = 0; local_r < BLOCK_SIZE; local_r++) {
            for (int local_c = 0; local_c < BLOCK_SIZE; local_c++) {
                int r = r_start + local_r;
                int c = c_start + local_c;

                if (r >= row || c >= col) continue;

                int idx = r * col + c;
                float delta;

                if (r == 0 && c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (temp[idx + col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == 0 && c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (temp[idx + col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == row - 1 && c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (temp[idx - col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == row - 1 && c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (temp[idx - col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (temp[idx + col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx - 1] - temp[idx]) * Rx_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (r == row - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (temp[idx - col] - temp[idx]) * Ry_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else if (c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx + 1] - temp[idx]) * Rx_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }
                else {
                    delta = Cap_1 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }

                result[idx] = temp[idx] + delta;
            }
        }
    }
}
